        import tempfile, base64 as _b64mod, os as _os
        _tmpl_bytes = _b64mod.b64decode(_TMPL_B64)
        _tmpl_fd, _TMPL_PATH = tempfile.mkstemp(suffix='.pptx', prefix='ltv_tmpl_')
        try:
            with _os.fdopen(_tmpl_fd, 'wb') as _f:
                _f.write(_tmpl_bytes)
        except Exception:
            _os.close(_tmpl_fd)
            raise

        from datetime import date
        from pptx import Presentation
        from pptx.oxml.ns import qn
        from pptx.opc.constants import RELATIONSHIP_TYPE as RT
        import copy

        # ── テンプレートを直接開く ──
        prs = Presentation(_TMPL_PATH)

        # ── ヘルパー関数 ──
        def _copy_slide(prs, from_idx):
            """指定スライドを複製して末尾に追加（マスタ・背景・画像完全維持）"""
            src = prs.slides[from_idx]
            new = prs.slides.add_slide(src.slide_layout)
            src_sp = src.shapes._spTree
            new_sp = new.shapes._spTree
            for el in list(new_sp)[2:]:
                new_sp.remove(el)
            for el in list(src_sp)[2:]:
                new_sp.append(copy.deepcopy(el))
            for rId, rel in src.part.rels.items():
                if rel.reltype == RT.IMAGE:
                    new.part.rels._rels[rId] = rel
            return new

        def _set_text(shape, text):
            """shapeの全runをクリアして最初のrunにテキストを設定"""
            if not shape.has_text_frame: return
            tf = shape.text_frame
            for _para in tf.paragraphs:
                for _run in _para.runs:
                    _run.text = ''
            if tf.paragraphs and tf.paragraphs[0].runs:
                tf.paragraphs[0].runs[0].text = text

        def _set_multiline(shape, text):
            """改行を含むテキストを段落ごとに設定"""
            if not shape.has_text_frame: return
            lines = text.split('\n')
            tf = shape.text_frame
            for i, para in enumerate(tf.paragraphs):
                if i < len(lines) and para.runs:
                    para.runs[0].text = lines[i]
                elif i < len(lines):
                    para.text = lines[i]

        def _replace_image(slide, shape, buf):
            """shapeの画像をbufの内容で差し替え"""
            blip = shape._element.find('.//' + qn('a:blip'))
            if blip is not None:
                buf.seek(0)
                img_part, new_rId = slide.part.get_or_add_image_part(buf)
                blip.set(qn('r:embed'), new_rId)

        def _set_table_row(tbl, row_idx, values):
            """テーブルのrow_idx行目に値をセット（全runクリア後に設定）"""
            if row_idx >= len(tbl.rows): return
            row = tbl.rows[row_idx]
            for c_idx, v in enumerate(values):
                if c_idx < len(row.cells):
                    tf = row.cells[c_idx].text_frame
                    for para in tf.paragraphs:
                        for run in para.runs:
                            run.text = ''
                    if tf.paragraphs and tf.paragraphs[0].runs:
                        tf.paragraphs[0].runs[0].text = str(v)

        # ── データ期間計算 ──
        _date_cols = [df['start_date']]
        if 'last_purchase_date' in df.columns and df['last_purchase_date'].notna().any():
            _date_cols.append(df['last_purchase_date'])
        if 'end_date' in df.columns and df['end_date'].notna().any():
            _date_cols.append(df['end_date'])
        _all_dates_flat = pd.concat(_date_cols).dropna()
        _data_start = _all_dates_flat.min().strftime('%Y/%m/%d')
        _data_end   = _all_dates_flat.max().strftime('%Y/%m/%d')

        # ══════════════════════════════════════════════
        # Slide 1: タイトル（テンプレートSlide1を更新）
        # ══════════════════════════════════════════════
        s1 = prs.slides[0]
        for sh in s1.shapes:
            if sh.name == 'TextBox 5':
                _set_text(sh, client_name or '')
            elif sh.name == 'TextBox 6':
                _set_text(sh, date.today().strftime('%Y年%m月%d日'))
            elif sh.name == 'TextBox 7':
                _set_text(sh, analyst_name or '')

        # ══════════════════════════════════════════════
        # Slide 2: 分析結果サマリー
        # ══════════════════════════════════════════════
        s2 = prs.slides[1]
        for sh in s2.shapes:
            n = sh.name
            if n == 'テキスト プレースホルダー 6':
                # billing_cycleの内部コードを表示名に変換
                _bc_disp = billing_cycle_display if 'billing_cycle_display' in dir() else billing_cycle.split('←')[0].strip()
                info1 = (
                    f"データ期間: {_data_start} – {_data_end}　|　"
                    f"顧客数: {len(df):,}件　|　解約済み: {df['event'].sum():,}件　|　"
                    f"継続中: {(df['event']==0).sum():,}件　|　"
                    f"平均日次 ARPU: ¥{arpu_daily:,.2f}　|　GPM: {gpm:.0%}"
                )
                info2 = (
                    f"異常値の処理：除外なし　|　{business_type}　|　"
                    f"{_bc_disp}　|　解約時の日割り計算：{'ON' if ltv_offset_days == 0 else 'OFF'}"
                )
                if sh.has_text_frame:
                    tf = sh.text_frame
                    # para0: 全runをクリアして最初のrunに設定
                    if len(tf.paragraphs) >= 1:
                        p0 = tf.paragraphs[0]
                        for r in p0.runs: r.text = ''
                        if p0.runs: p0.runs[0].text = info1
                    # para1: 全runをクリアして最初のrunに設定
                    if len(tf.paragraphs) >= 2:
                        p1 = tf.paragraphs[1]
                        for r in p1.runs: r.text = ''
                        if p1.runs: p1.runs[0].text = info2
            elif n == 'グループ化 26':
                kpi_map = {
                    'TextBox 6':  f'¥{ltv_rev:,.0f}',
                    'TextBox 10': f'¥{cac_upper:,.0f}',
                    'TextBox 11': f'CAC上限（{cac_label}）',
                    'TextBox 14': f'{k:.3f}',
                    'TextBox 18': f'{lam_actual:.0f}日',
                    'TextBox 22': f'{r2:.3f}',
                }
                for grp_sh in sh.shapes:
                    if grp_sh.name in kpi_map:
                        _set_text(grp_sh, kpi_map[grp_sh.name])
            elif n == 'テキスト ボックス 49':
                if sh.has_text_frame:
                    tf = sh.text_frame
                    # para0: '結論'
                    if len(tf.paragraphs) >= 1:
                        p0 = tf.paragraphs[0]
                        for r in p0.runs: r.text = ''
                        if p0.runs: p0.runs[0].text = '結論'
                    # para1: 本文（全runクリアして最初のrunに）
                    if len(tf.paragraphs) >= 2:
                        p1 = tf.paragraphs[1]
                        for r in p1.runs: r.text = ''
                        if p1.runs: p1.runs[0].text = k_summary + r2_summary

        # ══════════════════════════════════════════════
        # Slide 3: 分析の信頼性（Survival Curve / Weibull Plot）
        # ══════════════════════════════════════════════
        s3 = prs.slides[2]
        if k < 0.7:
            k_insight = f"k={k:.3f}（強い初期集中型）: 利用開始直後の体験品質が生死を分ける構造。30日以内の離脱防止施策が最重要。"
        elif k < 1.0:
            k_insight = f"k={k:.3f}（緩やかな初期集中型）: 離脱率は一定に近いが初期にやや多め。オンボーディング改善とリテンション施策を並行実施。"
        elif k < 1.5:
            k_insight = f"k={k:.3f}（逓増型・中程度）: 継続期間が長いほど離脱リスクが増す。1年超の顧客へのエンゲージメント強化が鍵。"
        else:
            k_insight = f"k={k:.3f}（強い逓増型）: 長期顧客ほど急速に離脱。VIP施策・継続特典による長期繋ぎ止めが急務。"
        lam_disp_s3 = lam + ltv_offset_days if business_type == '都度購入型' else lam
        if r2 >= 0.95:
            r2_comment = f"R²={r2:.3f}: 非常に高精度。LTV∞推定値の信頼性は高い。"
        elif r2 >= 0.85:
            r2_comment = f"R²={r2:.3f}: 許容範囲内。推定値に±15%程度の幅を見込んで意思決定を。"
        else:
            r2_comment = f"R²={r2:.3f}: やや低め。データ件数不足または複数の離脱パターンが混在している可能性あり。"
        for sh in s3.shapes:
            if sh.name == 'Picture 3':
                buf1.seek(0); _replace_image(s3, sh, buf1)
            elif sh.name == 'Picture 4':
                buf2.seek(0); _replace_image(s3, sh, buf2)
            elif sh.name == 'TextBox 7':
                k_text = (
                    f"k（形状パラメータ） = {k:.3f}\n"
                    f"→ 左グラフ（Survival Curve）の曲線の急峻さを決める値。k=1で指数分布（一定離脱率）\n"
                    f"→ {k_insight}"
                )
                if sh.has_text_frame:
                    tf = sh.text_frame
                    for para in tf.paragraphs:
                        for run in para.runs: run.text = ''
                    if tf.paragraphs and tf.paragraphs[0].runs:
                        tf.paragraphs[0].runs[0].text = k_text
            elif sh.name == 'TextBox 8':
                lam_text = (
                    f"λ（尺度パラメータ） = {lam_disp_s3:.1f}日（約{lam_disp_s3/365:.1f}年）\n"
                    f"→ 大きいほどLTV∞到達が長期化する。λ日時点での暫定LTV到達率はk値により異なる（k=1のとき63.2%）\n"
                    f"→ {r2_comment}"
                )
                if sh.has_text_frame:
                    tf = sh.text_frame
                    for para in tf.paragraphs:
                        for run in para.runs: run.text = ''
                    if tf.paragraphs and tf.paragraphs[0].runs:
                        tf.paragraphs[0].runs[0].text = lam_text

        # ══════════════════════════════════════════════
        # Slide 4: 暫定LTVテーブル
        # ══════════════════════════════════════════════
        s4 = prs.slides[3]
        all_rows_pp = []
        for h in horizons:
            if business_type == '都度購入型':
                _dorm_pp = dormancy_days or 180
                lh_r = ltv_horizon_spot(k, lam, arpu_0_dorm, arpu_long, h, _dorm_pp)
                lh_g = ltv_horizon_spot(k, lam, arpu_0_dorm*gpm, arpu_long*gpm, h, _dorm_pp)
            else:
                lh_r = ltv_horizon_offset(k, lam, arpu_daily, h, ltv_offset_days)
                lh_g = ltv_horizon_offset(k, lam, gp_daily, h, ltv_offset_days)
            label = f'{h}日' if h < 365 else f'{h//365}年（{h:,}日）'
            all_rows_pp.append((label, lh_r, lh_g, lh_g/cac_n, lh_r/ltv_rev*100))
        all_rows_pp.append((f'λ {round(lam_actual):,}日', lam_rev, lam_gp, lam_gp/cac_n, lam_rev/ltv_rev*100))
        all_rows_pp.append((f'LTV∞到達率: 99%（{int(days_99):,}日）', rev_99, gp_99, gp_99/cac_n, 99.0))

        for sh in s4.shapes:
            if sh.shape_type == 19:  # TABLE
                tbl = sh.table
                for r_idx, (label, lr, lg, lc, pct) in enumerate(all_rows_pp):
                    _set_table_row(tbl, r_idx + 1,
                        [label, f'¥{lr:,.0f}', f'¥{lg:,.0f}', f'¥{lc:,.0f}', f'{pct:.1f}%'])
            elif sh.name == 'テキスト ボックス 3':
                sh.top = int(4.60 * 914400)
                if sh.has_text_frame:
                    tf = sh.text_frame
                    k_type = '強い初期離脱型' if k < 0.7 else ('初期離脱型' if k < 1.0 else '逓増型')
                    from pptx.oxml.ns import qn as _qn4
                    from lxml import etree as _et4

                    def _make_run4(para, text, bold=False, color=None, size_pt=10):
                        r = _et4.SubElement(para._p, _qn4('a:r'))
                        rPr = _et4.SubElement(r, _qn4('a:rPr'), attrib={'lang':'ja-JP','altLang':'en-US','dirty':'0'})
                        if bold: rPr.set('b', '1')
                        rPr.set('sz', str(int(size_pt * 100)))
                        if color:
                            sf = _et4.SubElement(rPr, _qn4('a:solidFill'))
                            sc = _et4.SubElement(sf, _qn4('a:srgbClr'))
                            sc.set('val', color.replace('#','').upper())
                        t = _et4.SubElement(r, _qn4('a:t'))
                        t.text = text
                        return r

                    def _add_br4(para):
                        br = _et4.SubElement(para._p, _qn4('a:br'))
                        brPr = _et4.SubElement(br, _qn4('a:rPr'), attrib={'lang':'ja-JP','dirty':'0'})
                        return br

                    # 全runとa:brをクリア（pPrのbullet設定は保持）
                    for _pp in tf.paragraphs:
                        for _rr in list(_pp._p.findall(_qn4('a:r'))): _pp._p.remove(_rr)
                        for _br in list(_pp._p.findall(_qn4('a:br'))): _pp._p.remove(_br)

                    # 段落数調整（6段落必要）
                    while len(tf.paragraphs) < 6:
                        _et4.SubElement(tf._txBody, _qn4('a:p'))
                    _pp = tf.paragraphs

                    # para0: このテーブルの読み方（buNone=True, bullet無し）
                    _make_run4(_pp[0], 'このテーブルの読み方', bold=True, color='#3A6A7A', size_pt=10)

                    # para1: λ説明（bullet=•）
                    _make_run4(_pp[1], f'λ={round(lam_actual):,}日（約{lam_actual/365:.1f}年）は中程度の継続期間で、1〜2年継続する顧客が多いビジネスです。', color='#CCCCCC', size_pt=10)

                    # para2: k説明（bullet=•）
                    _make_run4(_pp[2], f'k={k:.3f}（{k_type}）: 契約直後に大量離脱するパターンです。LTV∞は大きく見えますが少数の超長期顧客の分が含まれており、99%到達まで長期間かかります。CAC投資判断には暫定LTV（現実的な期間）を使ってください。', color='#CCCCCC', size_pt=10)

                    # para3: LTV∞説明（bullet=•）本文 + 改行 + 年次データ
                    try:
                        _make_run4(_pp[3], f'LTV∞（¥{ltv_rev:,.0f}）は理論上の上限値で、実際にはこの金額に向かって時間をかけて積み上がります。', color='#CCCCCC', size_pt=10)
                        _add_br4(_pp[3])
                        _make_run4(_pp[3], '1年時点', color='#56B4D3', size_pt=10)
                        _make_run4(_pp[3], 'でLTV∞の', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[3], f'{all_rows_pp[1][4]:.1f}%', bold=True, color='#A8DADC', size_pt=10)
                        _make_run4(_pp[3], f'（¥{all_rows_pp[1][1]:,.0f}）、', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[3], '2年時点', color='#56B4D3', size_pt=10)
                        _make_run4(_pp[3], 'で', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[3], f'{all_rows_pp[2][4]:.1f}%', bold=True, color='#A8DADC', size_pt=10)
                        _make_run4(_pp[3], f'（¥{all_rows_pp[2][1]:,.0f}）、', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[3], '3年時点', color='#56B4D3', size_pt=10)
                        _make_run4(_pp[3], 'で', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[3], f'{all_rows_pp[3][4]:.1f}%', bold=True, color='#A8DADC', size_pt=10)
                        _make_run4(_pp[3], f'（¥{all_rows_pp[3][1]:,.0f}）に到達します。', color='#CCCCCC', size_pt=10)
                    except Exception: pass

                    # para4: CAC回収期間（bullet=•）— 内部で直接計算して確実に書く
                    try:
                        from scipy.optimize import brentq as _bq4
                        def _rec_str4(days):
                            return f"{days/365:.1f}年（{int(days):,}日）" if days >= 365 else f"{int(days)}日"
                        try:
                            _r4 = _bq4(lambda h: ltv_horizon_offset(k, lam, arpu_daily, h, ltv_offset_days) - cac_upper, 1, 36500)
                            _cac_rev_s = _rec_str4(_r4)
                        except Exception:
                            _cac_rev_s = cac_recover_rev_str if 'cac_recover_rev_str' in vars() else '算出不可'
                        try:
                            _g4 = _bq4(lambda h: ltv_horizon_offset(k, lam, gp_daily, h, ltv_offset_days) - cac_upper, 1, 36500)
                            _cac_gp_s = _rec_str4(_g4)
                        except Exception:
                            _cac_gp_s = cac_recover_gp_str if 'cac_recover_gp_str' in vars() else '算出不可'
                        _make_run4(_pp[4], f'CAC上限（¥{cac_upper:,.0f}）の回収期間：売上ベース 約 ', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[4], _cac_rev_s, bold=True, color='#A8DADC', size_pt=10)
                        _make_run4(_pp[4], ' / 粗利ベース 約 ', color='#CCCCCC', size_pt=10)
                        _make_run4(_pp[4], _cac_gp_s, bold=True, color='#56B4D3', size_pt=10)
                    except Exception: pass

                    # para5: CAC設計の目安（buNone=True, bullet無し）
                    _make_run4(_pp[5], 'CAC設計の目安', bold=True, color='#56B4D3', size_pt=10)
                    _make_run4(_pp[5], '：回収期間に迷ったら、 ', color='#CCCCCC', size_pt=10)
                    _make_run4(_pp[5], f'λ={round(lam_actual):,}日（約{lam_actual/365:.1f}年）時点の暫定LTV（粗利）¥{lam_gp:,.0f}', bold=True, color='#A8DADC', size_pt=10)
                    _make_run4(_pp[5], ' を用いてCAC上限を算出してください。λは多くの顧客が離脱するまでの期間の目安をデータが示した答えです。', color='#CCCCCC', size_pt=10)
        # ══════════════════════════════════════════════
        # ══════════════════════════════════════════════
        # Slide 5: 暫定LTVグラフ
        # ══════════════════════════════════════════════
        # matplotlib(軸) + Pillow(日本語テキスト合成)
        import matplotlib
        matplotlib.use('Agg')
        import matplotlib.pyplot as _plt5
        import matplotlib.ticker as _mticker5
        from PIL import Image as _PILImg5, ImageDraw as _PILDraw5, ImageFont as _PILFont5
        _PIL_FP5 = '/usr/share/fonts/truetype/fonts-japanese-gothic.ttf'
        try:
            _pf5 = _PILFont5.truetype(_PIL_FP5, 16)
            _pf5s = _PILFont5.truetype(_PIL_FP5, 14)
        except Exception:
            _pf5 = _PILFont5.load_default(); _pf5s = _pf5
        _DPI5 = 150
        _fig5, _ax5 = _plt5.subplots(figsize=(10, 3.5), dpi=_DPI5)
        _fig5.patch.set_facecolor('#111820'); _ax5.set_facecolor('#111820')
        _ax5.plot(t_range, rev_line, color='#56b4d3', lw=2)
        _ax5.plot(t_range, gp_line,  color='#a8dadc', lw=2, ls='--')
        _ax5.plot(t_range, cac_line, color='#4a7a8a', lw=1.5, ls=':')
        _ax5.axhline(ltv_rev, color='#56b4d3', lw=0.8, ls=':', alpha=0.5)
        _ax5.axvline(lam_actual, color='#a8dadc', lw=1.2, ls='--', alpha=0.7)
        _ax5.set_xticks([180, 365, 730, 1095, 1460, 1825])
        _ax5.set_xticklabels([' ']*6)
        _ax5.set_xlim(0, x_max + 50)
        _ax5.set_xlabel(' '); _ax5.set_ylabel(' ')
        _ax5.tick_params(colors='#888')
        _ax5.yaxis.set_major_formatter(_plt5.FuncFormatter(lambda v, _: f'¥{v:,.0f}'))
        _ax5.grid(True, alpha=0.2, color='#1a3040')
        for _sp5 in _ax5.spines.values(): _sp5.set_color('#1a3040')
        _fig5.tight_layout()
        _buf5r = io.BytesIO()
        _fig5.savefig(_buf5r, format='png', dpi=_DPI5, bbox_inches='tight', facecolor='#111820')
        _buf5r.seek(0)

        def _d2px5(ax, fig, x, y, dpi):
            disp = ax.transData.transform((x, y))
            return int(disp[0]), int(fig.get_size_inches()[1]*dpi - disp[1])

        _img5 = _PILImg5.open(_buf5r).convert('RGBA')
        _iw5, _ih5 = _img5.size
        _ov5 = _PILImg5.new('RGBA', (_iw5, _ih5), (0,0,0,0))
        _dr5 = _PILDraw5.Draw(_ov5)

        # X軸ラベル
        for _xv, _xl in zip([180,365,730,1095,1460,1825], ['180日','1年','2年','3年','4年','5年']):
            _px5, _py5 = _d2px5(_ax5, _fig5, _xv, _ax5.get_ylim()[0], _DPI5)
            _tw5 = _dr5.textlength(_xl, font=_pf5s)
            _dr5.text((int(_px5-_tw5/2), _py5+4), _xl, font=_pf5s, fill='#888888')

        # 凡例
        _legend_items = [('LTV（売上）','#56b4d3'), ('LTV（粗利）','#a8dadc'), ('CAC上限','#4a7a8a'), (f'LTV∞ ¥{ltv_rev:,.0f}','#56b4d3')]
        _lx, _ly = 70, 10
        for _lt, _lc in _legend_items:
            _dr5.rectangle([_lx, _ly+3, _lx+18, _ly+13], fill=_lc)
            _dr5.text((_lx+22, _ly), _lt, font=_pf5s, fill='white')
            _lx += int(_dr5.textlength(_lt, font=_pf5s)) + 50

        # 軸ラベル
        _, _mpy5 = _d2px5(_ax5, _fig5, _ax5.get_xlim()[0], (_ax5.get_ylim()[0]+_ax5.get_ylim()[1])/2, _DPI5)
        _dr5.text((2, int(_mpy5-8)), '金額（円）', font=_pf5s, fill='#888888')
        _cpx5, _cpy5 = _d2px5(_ax5, _fig5, (x_max+50)/2, _ax5.get_ylim()[0], _DPI5)
        _xt5 = '継続期間'
        _tw_xt5 = _dr5.textlength(_xt5, font=_pf5s)
        _dr5.text((int(_cpx5-_tw_xt5/2), _cpy5+22), _xt5, font=_pf5s, fill='#888888')

        _plt5.close()
        _res5 = _PILImg5.alpha_composite(_img5, _ov5).convert('RGB')
        _buf5 = io.BytesIO()
        _res5.save(_buf5, format='PNG')
        _buf5.seek(0)
        s5 = prs.slides[4]
        for sh in s5.shapes:
            if sh.name == 'コンテンツ プレースホルダー 6':
                _replace_image(s5, sh, _buf5)

        # ══════════════════════════════════════════════
        # Slide 6〜: セグメント別
        # ══════════════════════════════════════════════
        if segment_cols_input.strip():
            seg_cols_pp = [c.strip() for c in segment_cols_input.split(',')
                          if c.strip() and c.strip() in df.columns]

            # Slide 6: セグメント扉
            s6 = prs.slides[5]
            for sh in s6.shapes:
                if sh.name == 'TextBox 4':
                    if sh.has_text_frame and sh.text_frame.paragraphs:
                        p = sh.text_frame.paragraphs[0]
                        for run in p.runs: run.text = ''
                        if p.runs:
                            p.runs[0].text = '  |  '.join(seg_cols_pp)

            # 元のSlide7〜10を保持して後で複製に使う
            # （prs.slides[6]〜[9]がSlide7〜10）

            first_sc = True
            for sc in seg_cols_pp:
                # セグメントデータ計算
                seg_vals = df[sc].dropna().unique()
                pp_rows = []
                for sv in sorted(seg_vals):
                    df_s = df[df[sc] == sv]
                    if len(df_s) < 10 or df_s['event'].sum() < 5:
                        continue
                    try:
                        km_s = _compute_km_df(df_s)
                        k_s, lam_s, r2_s, _ = _fit_weibull_df(km_s)
                        if k_s is None: continue
                        arpu_s = (df_s['revenue_total'].sum() / df_s['duration'].sum()
                                 if billing_cycle == '日次（都度購入）'
                                 else df_s['arpu_daily'].mean())
                        gp_s = arpu_s * gpm
                        ltv_r, _ = ltv_inf(k_s, lam_s, arpu_s)
                        ltv_g, _ = ltv_inf(k_s, lam_s, gp_s)
                        pp_rows.append({'seg': str(sv), 'n': len(df_s),
                            'ltv_r': ltv_r, 'ltv_g': ltv_g, 'cac': ltv_g/cac_n,
                            'k': k_s, 'lam': lam_s, 'r2': r2_s})
                    except Exception:
                        continue
                if not pp_rows:
                    continue
                pp_rows.sort(key=lambda x: x['ltv_r'], reverse=True)
                best = pp_rows[0]
                avg_ltv = sum(r['ltv_r'] for r in pp_rows) / len(pp_rows)
                avg_cac = sum(r['cac']*r['n'] for r in pp_rows) / sum(r['n'] for r in pp_rows)  # 顧客数加重平均
                premium = (best['ltv_r'] - avg_ltv) / avg_ltv * 100
                cac_diff = best['cac'] - avg_cac

                # ── Slide 7: LTV∞比較棒グラフ ──
                s7 = _copy_slide(prs, 6)
